using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a JSON REST API via HttpClient.
/// Non-static class — services are injected through the constructor.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API. Returns a JSON array.")]
    public async Task<string> ListItems(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing all items");
        var items = await httpClient.GetFromJsonAsync<JsonElement>("items", cancellationToken);
        return JsonSerializer.Serialize(items, JsonOptions);
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique ID of the item to retrieve")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);
        var response = await httpClient.GetAsync($"items/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";
        }

        var item = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(item, JsonOptions);
    }

    [McpServerTool, Description("Create a new item. Provide the item data as a JSON string.")]
    public async Task<string> CreateItem(
        [Description("JSON object representing the new item, e.g. {\"title\":\"Buy milk\"}")] string itemJson,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item");
        var content = new StringContent(itemJson, System.Text.Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("items", content, cancellationToken);

        var body = await response.Content.ReadAsStringAsync(cancellationToken);
        return response.IsSuccessStatusCode
            ? $"Created successfully:\n{body}"
            : $"Error: {(int)response.StatusCode} {response.ReasonPhrase}\n{body}";
    }

    [McpServerTool(Destructive = true),
     Description("Delete an item by its unique identifier.")]
    public async Task<string> DeleteItem(
        [Description("The unique ID of the item to delete")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Deleting item {Id}", id);
        var response = await httpClient.DeleteAsync($"items/{id}", cancellationToken);

        return response.IsSuccessStatusCode
            ? $"Item {id} deleted."
            : $"Error: {(int)response.StatusCode} {response.ReasonPhrase}";
    }
}

